+import {
+  Button,
+  Callout,
+  Card,
+  CardBody,
+  CardHeader,
+  Grid,
+  H1,
+  H2,
+  Pill,
+  Row,
+  Select,
+  Stack,
+  Stat,
+  Text,
+  TextArea,
+  TextInput,
+  useCanvasState,
+  useHostTheme,
+} from "cursor/canvas";
+
+type Agreement = "unset" | "yes" | "partial" | "no";
+type Confidence = "unset" | "high" | "medium" | "low";
+
+type UserValidation = {
+  id: number;
+  userName: string;
+  chatsReviewed: string;
+  dateRange: string;
+  bestSession: string;
+  bestAgree: Agreement;
+  nearMissSession: string;
+  nearMissAgree: Agreement;
+  worstSession: string;
+  worstAgree: Agreement;
+  gotRight: string;
+  missed: string;
+  rubricChange: string;
+  confidence: Confidence;
+};
+
+const agreementOptions = [
+  { value: "unset", label: "Not checked" },
+  { value: "yes", label: "Yes" },
+  { value: "partial", label: "Partial" },
+  { value: "no", label: "No" },
+];
+
+const confidenceOptions = [
+  { value: "unset", label: "Not decided" },
+  { value: "high", label: "High" },
+  { value: "medium", label: "Medium" },
+  { value: "low", label: "Low" },
+];
+
+const defaultUsers: UserValidation[] = [1, 2, 3, 4, 5].map((id) => ({
+  id,
+  userName: `User ${id}`,
+  chatsReviewed: "",
+  dateRange: "",
+  bestSession: "",
+  bestAgree: "unset",
+  nearMissSession: "",
+  nearMissAgree: "unset",
+  worstSession: "",
+  worstAgree: "unset",
+  gotRight: "",
+  missed: "",
+  rubricChange: "",
+  confidence: "unset",
+}));
+
+function countAgreement(users: UserValidation[], field: keyof UserValidation) {
+  return users.reduce(
+    (total, user) => {
+      const value = user[field];
+      if (value === "yes") return { ...total, yes: total.yes + 1 };
+      if (value === "partial") return { ...total, partial: total.partial + 1 };
+      if (value === "no") return { ...total, no: total.no + 1 };
+      return total;
+    },
+    { yes: 0, partial: 0, no: 0 },
+  );
+}
+
+function agreementScore(users: UserValidation[]) {
+  const fields: Array<keyof UserValidation> = ["bestAgree", "nearMissAgree", "worstAgree"];
+  let checked = 0;
+  let score = 0;
+
+  users.forEach((user) => {
+    fields.forEach((field) => {
+      const value = user[field];
+      if (value === "yes") {
+        checked += 1;
+        score += 1;
+      } else if (value === "partial") {
+        checked += 1;
+        score += 0.5;
+      } else if (value === "no") {
+        checked += 1;
+      }
+    });
+  });
+
+  return checked === 0 ? "0%" : `${Math.round((score / checked) * 100)}%`;
+}
+
+function Field({
+  label,
+  children,
+}: {
+  label: string;
+  children: React.ReactNode;
+}) {
+  return (
+    <Stack gap={6}>
+      <Text size="small" tone="secondary" weight="semibold">
+        {label}
+      </Text>
+      {children}
+    </Stack>
+  );
+}
+
+function AgreementSummary({
+  label,
+  users,
+  field,
+}: {
+  label: string;
+  users: UserValidation[];
+  field: keyof UserValidation;
+}) {
+  const counts = countAgreement(users, field);
+  return (
+    <Row gap={8} align="center" wrap>
+      <Text weight="semibold">{label}</Text>
+      <Pill active={counts.yes >= 4}>Yes: {counts.yes}/5</Pill>
+      <Pill active={counts.partial > 0}>Partial: {counts.partial}/5</Pill>
+      <Pill active={counts.no > 0}>No: {counts.no}/5</Pill>
+    </Row>
+  );
+}
+
+export default function RubricValidationCheckpoint() {
+  const theme = useHostTheme();
+  const [users, setUsers] = useCanvasState<UserValidation[]>("validation-users", defaultUsers);
+  const [finalConclusion, setFinalConclusion] = useCanvasState(
+    "final-conclusion",
+    "The rubric is / is not reliable enough to continue implementation because...",
+  );
+  const [majorStrengths, setMajorStrengths] = useCanvasState("major-strengths", "");
+  const [majorLoopholes, setMajorLoopholes] = useCanvasState("major-loopholes", "");
+  const [nextChanges, setNextChanges] = useCanvasState("next-changes", "");
+
+  const totalChats = users.reduce((sum, user) => {
+    const value = Number.parseInt(user.chatsReviewed, 10);
+    return Number.isFinite(value) ? sum + value : sum;
+  }, 0);
+  const usersValidated = users.filter((user) =>
+    [user.bestAgree, user.nearMissAgree, user.worstAgree].some((value) => value !== "unset"),
+  ).length;
+  const alignment = agreementScore(users);
+
+  function updateUser(id: number, patch: Partial<UserValidation>) {
+    setUsers((current) =>
+      current.map((user) => (user.id === id ? { ...user, ...patch } : user)),
+    );
+  }
+
+  return (
+    <Stack gap={20} style={{ padding: 20, color: theme.text.primary }}>
+      <Stack gap={8}>
+        <H1>Rubric Validation Checkpoint</H1>
+        <Text tone="secondary">
+          Use this during one-on-one feedback. Run the current rubric as-is, show each user
+          the best, near-miss, and worst sessions, then record whether the human judgment
+          agrees with the rubric.
+        </Text>
+      </Stack>
+
+      <Grid columns={3} gap={16}>
+        <Stat value={`${usersValidated}/5`} label="Users with feedback" tone={usersValidated >= 5 ? "success" : "info"} />
+        <Stat value={totalChats} label="Cursor chats reviewed" />
+        <Stat value={alignment} label="Human alignment score" tone={alignment === "0%" ? "warning" : "success"} />
+      </Grid>
+
+      <Callout tone="info" title="Decision rule">
+        If at least 4 out of 5 users agree with the rubric's best and worst judgments, the
+        rubric is directionally useful. If agreement is lower, use the disagreement cases to
+        revise the rubric before continuing implementation.
+      </Callout>
+
+      <Stack gap={10}>
+        <H2>Agreement Matrix</H2>
+        <Stack gap={8} style={{ padding: 12, border: `1px solid ${theme.stroke.tertiary}`, borderRadius: 8 }}>
+          <AgreementSummary label="Best session" users={users} field="bestAgree" />
+          <AgreementSummary label="Near-miss session" users={users} field="nearMissAgree" />
+          <AgreementSummary label="Worst session" users={users} field="worstAgree" />
+        </Stack>
+      </Stack>
+
+      <Grid columns="repeat(2, minmax(0, 1fr))" gap={16} align="start">
+        {users.map((user) => (
+          <Card key={user.id} collapsible defaultOpen={user.id <= 2}>
+            <CardHeader trailing={<Pill size="sm" active={user.confidence === "high"}>{user.confidence === "unset" ? "Pending" : user.confidence}</Pill>}>
+              {user.userName || `User ${user.id}`}
+            </CardHeader>
+            <CardBody>
+              <Stack gap={14}>
+                <Grid columns={2} gap={12}>
+                  <Field label="User name">
+                    <TextInput
+                      value={user.userName}
+                      onChange={(value) => updateUser(user.id, { userName: value })}
+                    />
+                  </Field>
+                  <Field label="No. of chats reviewed">
+                    <TextInput
+                      type="number"
+                      value={user.chatsReviewed}
+                      onChange={(value) => updateUser(user.id, { chatsReviewed: value })}
+                      placeholder="0"
+                    />
+                  </Field>
+                </Grid>
+
+                <Field label="Chat date range">
+                  <TextInput
+                    value={user.dateRange}
+                    onChange={(value) => updateUser(user.id, { dateRange: value })}
+                    placeholder="Example: Jun 18-19"
+                  />
+                </Field>
+
+                <Grid columns="1fr 150px" gap={12} align="end">
+                  <Field label="Rubric best session">
+                    <TextArea
+                      rows={2}
+                      value={user.bestSession}
+                      onChange={(value) => updateUser(user.id, { bestSession: value })}
+                      placeholder="Session title/link + rubric reason"
+                    />
+                  </Field>
+                  <Field label="User agrees?">
+                    <Select
+                      value={user.bestAgree}
+                      onChange={(value) => updateUser(user.id, { bestAgree: value as Agreement })}
+                      options={agreementOptions}
+                    />
+                  </Field>
+                </Grid>
+
+                <Grid columns="1fr 150px" gap={12} align="end">
+                  <Field label="Rubric near-miss session">
+                    <TextArea
+                      rows={2}
+                      value={user.nearMissSession}
+                      onChange={(value) => updateUser(user.id, { nearMissSession: value })}
+                      placeholder="Session title/link + rubric reason"
+                    />
+                  </Field>
+                  <Field label="User agrees?">
+                    <Select
+                      value={user.nearMissAgree}
+                      onChange={(value) => updateUser(user.id, { nearMissAgree: value as Agreement })}
+                      options={agreementOptions}
+                    />
+                  </Field>
+                </Grid>
+
+                <Grid columns="1fr 150px" gap={12} align="end">
+                  <Field label="Rubric worst session">
+                    <TextArea
+                      rows={2}
+                      value={user.worstSession}
+                      onChange={(value) => updateUser(user.id, { worstSession: value })}
+                      placeholder="Session title/link + rubric reason"
+                    />
+                  </Field>
+                  <Field label="User agrees?">
+                    <Select
+                      value={user.worstAgree}
+                      onChange={(value) => updateUser(user.id, { worstAgree: value as Agreement })}
+                      options={agreementOptions}
+                    />
+                  </Field>
+                </Grid>
+
+                <Grid columns={2} gap={12}>
+                  <Field label="What rubric got right">
+                    <TextArea
+                      rows={3}
+                      value={user.gotRight}
+                      onChange={(value) => updateUser(user.id, { gotRight: value })}
+                    />
+                  </Field>
+                  <Field label="What rubric missed">
+                    <TextArea
+                      rows={3}
+                      value={user.missed}
+                      onChange={(value) => updateUser(user.id, { missed: value })}
+                    />
+                  </Field>
+                </Grid>
+
+                <Grid columns="1fr 150px" gap={12} align="end">
+                  <Field label="Rubric change needed">
+                    <TextArea
+                      rows={3}
+                      value={user.rubricChange}
+                      onChange={(value) => updateUser(user.id, { rubricChange: value })}
+                    />
+                  </Field>
+                  <Field label="Final confidence">
+                    <Select
+                      value={user.confidence}
+                      onChange={(value) => updateUser(user.id, { confidence: value as Confidence })}
+                      options={confidenceOptions}
+                    />
+                  </Field>
+                </Grid>
+              </Stack>
+            </CardBody>
+          </Card>
+        ))}
+      </Grid>
+
+      <Card size="lg">
+        <CardHeader>Final validation conclusion</CardHeader>
+        <CardBody>
+          <Stack gap={14}>
+            <Grid columns={3} gap={12}>
+              <Field label="Major rubric strengths">
+                <TextArea rows={5} value={majorStrengths} onChange={setMajorStrengths} />
+              </Field>
+              <Field label="Major rubric loopholes">
+                <TextArea rows={5} value={majorLoopholes} onChange={setMajorLoopholes} />
+              </Field>
+              <Field label="Rubric changes required">
+                <TextArea rows={5} value={nextChanges} onChange={setNextChanges} />
+              </Field>
+            </Grid>
+            <Field label="Final decision">
+              <TextArea rows={4} value={finalConclusion} onChange={setFinalConclusion} />
+            </Field>
+            <Row gap={8} align="center">
+              <Button
+                variant="secondary"
+                onClick={() => {
+                  setUsers(defaultUsers);
+                  setMajorStrengths("");
+                  setMajorLoopholes("");
+                  setNextChanges("");
+                  setFinalConclusion(
+                    "The rubric is / is not reliable enough to continue implementation because...",
+                  );
+                }}
+              >
+                Reset worksheet
+              </Button>
+              <Text size="small" tone="tertiary">
+                Reset only after you have copied or summarized the completed feedback.
+              </Text>
+            </Row>
+          </Stack>
+        </CardBody>
+      </Card>
+    </Stack>
+  );
+}
*** End Patch
